class Solution {
    public String reformatNumber(String number) {
        StringBuilder sb = new StringBuilder();
        for (char c : number.toCharArray()) {
            if (c != ' ' && c != '-') {
                sb.append(c);
            }
        }
        int n = sb.length();
        while (n > 4) {
            sb.insert(3, '-');
            n -= 3;
        }
        if (n == 4) {
            sb.insert(2, '-');
        }
        return sb.toString();
    }
}
```

